'use client';
import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { PageContainer } from '@/src/components/layout';
import { Button } from '@/src/components/ui';
import Img from '@/src/components/ui/Img';
import { useCart } from '@/src/context/CartContext';

const CartPage: React.FC = () => {
  const router = useRouter();
  const { items, removeItem, updateQuantity, clearCart, getTotalPrice } = useCart();

  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleCheckout = () => {
    router.push('/checkout');
  };

  const handleContinueShopping = () => {
    router.push('/catalog');
  };

  if (!mounted) {
    return null; // Return null on server and first client render to avoid hydration mismatch
  }

  return (
    <PageContainer>
      <div className="min-h-screen px-4 sm:px-6 md:px-8 lg:px-12 pt-6 sm:pt-8 md:pt-10 pb-24 sm:pb-16 md:pb-20">
        <div className="max-w-7xl mx-auto">
          {/* Page Title */}
          <div className="text-center mb-6 sm:mb-8 md:mb-10 lg:mb-12 content-reveal content-reveal-delay-1">
            <h1 className="text-white font-manrope font-bold text-2xl sm:text-3xl md:text-4xl lg:text-5xl mb-2 sm:mb-3 md:mb-4 drop-shadow-[0_4px_12px_rgba(0,0,0,0.9)]">
              Корзина
            </h1>
            <div className="w-16 sm:w-20 md:w-24 lg:w-32 h-0.5 sm:h-1 bg-white/40 mx-auto"></div>
          </div>

          {/* Background container */}
          <div className="border border-white/20 rounded-lg sm:rounded-xl p-6 sm:px-8 md:p-10">

            {items.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 sm:py-12 md:py-16 content-reveal">
                {/* Empty Cart State */}
                <div className="border border-white/20 rounded-lg sm:rounded-xl p-6 sm:p-8 md:p-10 max-w-2xl text-center w-full">
                  {/* Shine effect */}
                  <div className="absolute inset-0 bg-gradient-to-br from-white/5 via-transparent to-transparent pointer-events-none" />

                  <div className="relative z-10 p-6 sm:p-10 md:p-16">
                    <div className="mb-6 sm:mb-8">
                      <svg
                        className="w-20 h-20 sm:w-28 sm:h-28 md:w-32 md:h-32 mx-auto text-white/20"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={1.5}
                          d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"
                        />
                      </svg>
                    </div>
                    <h2 className="text-xl sm:text-2xl md:text-3xl font-manrope font-bold text-white mb-3 sm:mb-4">
                      Корзина пуста
                    </h2>
                    <p className="text-base sm:text-lg md:text-xl text-white/60 mb-6 sm:mb-8">
                      Добавьте товары из каталога, чтобы оформить заказ
                    </p>
                    <Button onClick={handleContinueShopping} variant="primary" size="lg">
                      Перейти в каталог
                    </Button>
                  </div>
                </div>
              </div>
            ) : (
              /* Cart with Items */
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6 md:gap-8">
                {/* Cart Items - Left Column */}
                <div className="lg:col-span-2 space-y-4 scroll-fade-in scroll-fade-in-delay-1">
                  {items.map((item) => (
                    <div
                      key={item.id}
                      className="relative rounded-2xl bg-black/40 border border-white/10 transition-all duration-300"
                    >
                      {/* Shine effect on hover */}
                      <div className="absolute inset-0 opacity-0 hover:opacity-100 transition-opacity duration-500 overflow-hidden rounded-2xl pointer-events-none">
                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent translate-x-[-100%] hover:translate-x-[100%] transition-transform duration-1000" />
                      </div>

                      <div className="relative z-10 p-6 flex gap-6">
                        {/* Product Image */}
                        <div className="flex-shrink-0 w-32 h-32 bg-white/5 rounded-xl p-2">
                          <Img
                            src={item.image}
                            alt={item.title}
                            className="w-full h-full object-contain"
                          />
                        </div>

                        {/* Product Info */}
                        <div className="flex-1 flex flex-col justify-between">
                          <div>
                            <h3 className="text-xl font-manrope font-bold text-white mb-1">
                              {item.title}
                            </h3>
                            {item.subtitle && (
                              <p className="text-white/70 font-manrope mb-2">
                                {item.subtitle}
                              </p>
                            )}
                            <div className="flex flex-wrap gap-4 text-sm text-white/60">
                              {item.selectedSize && (
                                <span>Размер: {item.selectedSize}</span>
                              )}
                              {item.selectedColor && (
                                <span>Цвет: {item.selectedColor}</span>
                              )}
                              {item.selectedType && (
                                <span>Тип: {item.selectedType}</span>
                              )}
                            </div>
                          </div>

                          {/* Price and Controls */}
                          <div className="flex items-center justify-between mt-4">
                            <div className="text-2xl font-manrope font-bold text-white">
                              {item.price}
                            </div>

                            {/* Quantity Controls */}
                            <div className="flex items-center gap-4">
                              <div className="flex items-center gap-3 bg-white/5 rounded-lg px-4 py-2">
                                <Button
                                  onClick={() =>
                                    updateQuantity(item.id, item.quantity - 1)
                                  }
                                  variant="secondary"
                                  size="icon"
                                >
                                  −
                                </Button>
                                <span className="text-white font-manrope font-semibold text-lg min-w-[2rem] text-center">
                                  {item.quantity}
                                </span>
                                <Button
                                  onClick={() =>
                                    updateQuantity(item.id, item.quantity + 1)
                                  }
                                  variant="secondary"
                                  size="icon"
                                >
                                  +
                                </Button>
                              </div>

                              {/* Remove Button */}
                              <Button
                                onClick={() => removeItem(item.id)}
                                variant="danger"
                                size="icon"
                                aria-label="Удалить товар"
                              >
                                <svg
                                  className="w-6 h-6"
                                  fill="none"
                                  stroke="currentColor"
                                  viewBox="0 0 24 24"
                                >
                                  <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth={2}
                                    d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                                  />
                                </svg>
                              </Button>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Order Summary - Right Column */}
                <div className="lg:col-span-1 scroll-fade-in scroll-fade-in-delay-2">
                  <div className="relative rounded-2xl sticky top-24 bg-black/40 border border-white/10">
                    {/* Shine effect */}
                    <div className="absolute inset-0 bg-gradient-to-br from-white/5 via-transparent to-transparent pointer-events-none" />

                    <div className="relative z-10 p-8">
                      <h2 className="text-3xl font-manrope font-bold text-white mb-8">
                        Итого
                      </h2>

                      <div className="space-y-6 mb-8">
                        <div className="flex justify-between text-white/70 text-lg">
                          <span className="font-manrope">Товары:</span>
                          <span className="font-manrope font-semibold">
                            {items.reduce((sum, item) => sum + item.quantity, 0)} шт
                          </span>
                        </div>
                        <div className="w-full h-px bg-gradient-to-r from-transparent via-white/20 to-transparent" />
                        <div className="flex justify-between text-white text-2xl">
                          <span className="font-manrope font-bold">Сумма:</span>
                          <span className="font-manrope font-extrabold">
                            {getTotalPrice} р.
                          </span>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <Button
                          onClick={handleCheckout}
                          variant="primary"
                          size="xl"
                          fullWidth
                        >
                          Оформить заказ
                        </Button>

                        <Button
                          onClick={handleContinueShopping}
                          variant="secondary"
                          size="lg"
                          fullWidth
                        >
                          Продолжить покупки
                        </Button>

                        <Button
                          onClick={clearCart}
                          variant="danger"
                          size="md"
                          fullWidth
                        >
                          Очистить корзину
                        </Button>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </PageContainer>
  );
};

export default CartPage;

'use client';
import React, { useState, useEffect, useCallback } from 'react';
import { PageContainer, BottomSheet } from '@/src/components/layout';
import { CategorySelector, FiltersPanel, ProductGrid, ActiveFilters } from '@/src/components/products';
import { useProductFilters, useProductNavigation, useCatalogFilters, useFilterCounts, useActiveFilters } from '@/src/hooks';
import { useDeviceDetection } from '@/src/hooks';
import { API_CONFIG } from '@/src/constants/config';
import { ALL_PRODUCTS } from '@/src/lib/products';
import type { Product } from '@/src/types';
import { Button } from '@/src/components/ui';

/**
 * Catalog Page Component
 * Refactored with cleaner separation of concerns:
 * - Filter state managed by useCatalogFilters hook
 * - Filter logic in separate model layer
 * - Product fetching and rendering isolated
 */
const CatalogPage: React.FC = () => {
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const { isMobile } = useDeviceDetection();

  // Use custom hook for filter management
  const {
    sortBy,
    categoryFilter,
    colorFilter,
    sizeFilter,
    clothingTypeFilter,
    collectionFilter,
    pendingColorFilter,
    pendingSizeFilter,
    pendingClothingTypeFilter,
    pendingCollectionFilter,
    priceRange,
    minRating,
    dispatch,
    toggleFilterValue,
    applyFilters,
    resetAllFilters,
    hasPendingChanges,
    removeActiveFilter,
    clearAllActiveFilters,
  } = useCatalogFilters();

  // Fetch products from API or use static data
  useEffect(() => {
    const fetchProducts = async () => {
      // Use static data in production if no API URL is configured
      if (API_CONFIG.USE_STATIC_DATA) {
        setProducts(ALL_PRODUCTS);
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        const response = await fetch(`${API_CONFIG.BASE_URL}/products`);
        const data = await response.json();
        setProducts(data);
      } catch (error) {
        console.error('Error fetching products:', error);
        // Fallback to static data on error
        setProducts(ALL_PRODUCTS);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, []);

  // Preload critical product images for better performance
  useEffect(() => {
    if (products.length > 0) {
      // Preload first 6 product images
      const imagesToPreload = products.slice(0, 6).map(product => product.image);
      imagesToPreload.forEach(imageSrc => {
        const img = new Image();
        img.src = imageSrc.startsWith('/') ? `${process.env.PUBLIC_URL || ''}${imageSrc}` : imageSrc;
      });
    }
  }, [products]);

  // Use custom hooks for filtering and navigation
  const { navigateToProduct } = useProductNavigation();
  const filteredProducts = useProductFilters(products, {
    sortBy,
    categoryFilter,
    colorFilter,
    sizeFilter,
    clothingTypeFilter,
    collectionFilter,
    priceRange,
    minRating
  });

  // Handler for product card clicks
  const handleProductClick = useCallback((productData: any) => {
    // Find full product data by id
    const fullProduct = products.find(p => p.id === productData.id);
    if (fullProduct) {
      navigateToProduct(fullProduct);
    }
  }, [products, navigateToProduct]);

  // Reset size filter when category changes to avoid conflicts between mousepad/clothing sizes
  useEffect(() => {
    // Reset size filter when switching to/from mousepads category
    const clothingCategories = ['tshirt', 'hoodie', 'sleeve'];
    const isSwitchingToMousepads = categoryFilter === 'mousepads';
    const isSwitchingFromMousepads = clothingCategories.includes(categoryFilter);

    if (isSwitchingToMousepads || isSwitchingFromMousepads) {
      dispatch({ type: 'SET_SIZE_FILTER', payload: [] });
      dispatch({ type: 'SET_PENDING_SIZE_FILTER', payload: [] });
    }
  }, [categoryFilter]);

  // Wrap applyFilters to close modal
  const handleApplyFilters = useCallback(() => {
    applyFilters();
    setFiltersOpen(false);
  }, [applyFilters]);

  // Wrap resetAllFilters to close modal
  const handleResetFilters = useCallback(() => {
    resetAllFilters();
    setFiltersOpen(false);
  }, [resetAllFilters]);

  // Use custom hook for filter counts
  const { getCountForFilter } = useFilterCounts({
    products,
    categoryFilter,
    colorFilter,
    sizeFilter,
    clothingTypeFilter,
    collectionFilter,
    priceRange,
    minRating
  });

  // Use custom hook for active filters
  const activeFilters = useActiveFilters(colorFilter, sizeFilter, clothingTypeFilter, collectionFilter);

  return (
    <PageContainer>
      <div className="max-w-[1800px] mx-auto px-3 sm:px-4 md:px-6 lg:px-8 pt-4 sm:pt-6 md:pt-8 pb-24 sm:pb-12 md:pb-16">
        {/* Content container */}
        <div>
          {/* Page Title - SIMPLIFIED for mobile */}
          <div className="text-center mb-4 sm:mb-6 md:mb-8 content-reveal content-reveal-delay-1">
            <h1 className="text-2xl sm:text-3xl md:text-4xl font-bold text-white mb-2 sm:mb-3 drop-shadow-[0_4px_12px_rgba(0,0,0,0.9)]">
              Каталог товаров
            </h1>
            <div className="w-12 sm:w-16 md:w-20 h-0.5 bg-white/40 mx-auto"></div>
          </div>

          {/* Category Filter - moved here */}
          <CategorySelector
            categoryFilter={categoryFilter}
            onCategoryChange={(category) => dispatch({ type: 'SET_CATEGORY_FILTER', payload: category })}
          />

          {/* Mobile filter button - Enhanced with badges */}
          <div className="lg:hidden mb-3">
            <Button
              onClick={() => setFiltersOpen(!filtersOpen)}
              className="w-full min-h-[48px] bg-black/40 text-white font-semibold px-4 py-2.5 rounded-xl border border-white/20 hover:bg-black/50 active:bg-black/60 transition-all flex items-center justify-between text-sm gap-2"
              variant="secondary"
              size="md"
              fullWidth
              aria-expanded={filtersOpen}
              aria-controls="filters-panel"
              aria-label={filtersOpen ? "Скрыть фильтры" : "Показать фильтры"}
            >
              <div className="flex items-center gap-2">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="flex-shrink-0">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
                </svg>
                <span>Фильтры</span>
                {activeFilters.length > 0 && (
                  <span className="bg-blue-500 text-white text-xs font-bold px-1.5 py-0.5 rounded-full min-w-[18px] text-center">
                    {activeFilters.length}
                  </span>
                )}
              </div>
              <svg
                width="18"
                height="18"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                className="transition-transform flex-shrink-0"
                aria-hidden="true"
              >
                <path d="M9 5l7 7-7 7" />
              </svg>
            </Button>
          </div>

          {/* Active Filters Display */}
          <div className="mb-3">
            <ActiveFilters
              filters={activeFilters}
              onRemove={removeActiveFilter}
              onClearAll={clearAllActiveFilters}
              totalResults={filteredProducts.length}
            />
          </div>

          <div className="flex flex-col lg:flex-row gap-3 sm:gap-4 md:gap-5 lg:gap-6">
            {/* Filters Sidebar - Desktop */}
            <aside className="hidden lg:block lg:w-64 xl:w-72 w-full flex-shrink-0" id="filters-panel">
              <FiltersPanel
                sortBy={sortBy}
                onSortChange={(sort) => dispatch({ type: 'SET_SORT_BY', payload: sort })}
                categoryFilter={categoryFilter}
                pendingCollectionFilter={pendingCollectionFilter as any}
                pendingSizeFilter={pendingSizeFilter}
                pendingClothingTypeFilter={pendingClothingTypeFilter}
                priceRange={priceRange}
                onPriceRangeChange={(range) => dispatch({ type: 'SET_PRICE_RANGE', payload: range })}
                onToggleFilter={toggleFilterValue}
                onApplyFilters={handleApplyFilters}
                onResetFilters={handleResetFilters}
                hasPendingChanges={hasPendingChanges}
                getFilterCounts={{ getCountForFilter }}
              />
            </aside>

            {/* Products Grid */}
            <div className="flex-1">
              <ProductGrid
                products={filteredProducts}
                loading={loading}
                onProductClick={handleProductClick}
              />
            </div>
          </div>

          {/* Mobile Filters - BottomSheet */}
          {isMobile && (
            <BottomSheet
              isOpen={filtersOpen}
              onClose={() => setFiltersOpen(false)}
              title="Фильтры и сортировка"
              height="full"
              footer={
                <div className="flex gap-3">
                  <Button
                    onClick={handleResetFilters}
                    className="flex-1 min-h-[48px]"
                    variant="secondary"
                    size="md"
                    fullWidth
                  >
                    Сбросить
                  </Button>
                  <Button
                    onClick={handleApplyFilters}
                    className="flex-1 min-h-[48px]"
                    variant="primary"
                    size="md"
                    fullWidth
                  >
                    Применить {activeFilters.length > 0 && `(${activeFilters.length})`}
                  </Button>
                </div>
              }
            >
              <FiltersPanel
                sortBy={sortBy}
                onSortChange={(sort) => dispatch({ type: 'SET_SORT_BY', payload: sort })}
                categoryFilter={categoryFilter}
                pendingCollectionFilter={pendingCollectionFilter as any}
                pendingSizeFilter={pendingSizeFilter}
                pendingClothingTypeFilter={pendingClothingTypeFilter}
                priceRange={priceRange}
                onPriceRangeChange={(range) => dispatch({ type: 'SET_PRICE_RANGE', payload: range })}
                onToggleFilter={toggleFilterValue}
                onApplyFilters={handleApplyFilters}
                onResetFilters={handleResetFilters}
                hasPendingChanges={hasPendingChanges}
                getFilterCounts={{ getCountForFilter }}
              />
            </BottomSheet>
          )}
        </div>
      </div>
    </PageContainer>
  );
};

export default CatalogPage;

