/**
 * Hook for managing product images based on selected options
 */
export const useProductImages = (
  productData: Product | undefined,
  selectedSize: string,
  selectedColor: string
) => {
  return useMemo(() => {
    if (!productData) return [];

    const mainImage = productData.image;
    const baseUrl = process.env.PUBLIC_URL || '';

    // Helper function to get dynamic main image for geoid mousepads
    const getGeoidMainImage = (size: string, color: string): string => {
      const imageMap: Record<string, Record<string, string>> = {
        'XL': {
          'black': `${baseUrl}/images/products/mousepads/xl/xl_black_geoid/Generated Image October 30, 2025 - 6_24PM.png`,
          'white': `${baseUrl}/images/products/mousepads/xl/xl_white_geoid/Generated Image October 30, 2025 - 6_26PM.png`,
          'red': `${baseUrl}/images/products/mousepads/xl/xl_red/Generated Image October 30, 2025 - 6_25PM (1).png`,
          'blue': `${baseUrl}/images/products/mousepads/xl/xl_blue/Generated Image October 30, 2025 - 6_25PM.png`,
        },
        'L': {
          'black': `${baseUrl}/images/products/mousepads/l/l_black_geoid/Generated Image October 30, 2025 - 6_08PM.png`,
          'white': `${baseUrl}/images/products/mousepads/l/l_white_geoid/Generated Image October 30, 2025 - 6_11PM.png`,
          'red': `${baseUrl}/images/products/mousepads/l/l_red/Generated Image October 30, 2025 - 6_09PM (1).png`,
          'blue': `${baseUrl}/images/products/mousepads/l/l_blue/Generated Image October 30, 2025 - 6_09PM.png`,
        }
      };

      return imageMap[size]?.[color] || mainImage;
    };

    // Dynamic images for mousepads based on size and color
    if (productData.category === 'mousepads') {
      // Pro Speed poron mousepad
      if (productData.subtitle?.toLowerCase().includes('pro speed') && productData.subtitle.toLowerCase().includes('poron')) {
        return [
          mainImage,
          '/images/products/mousepads/pro/pro-speed_black_pro_01.webp',
          '/images/products/mousepads/pro/pro-speed_black_pro_02.webp',
          '/images/products/mousepads/pro/pro-speed_black_pro_03.webp'
        ];
      }

      // Logo-blue mousepad
      if (productData.subtitle?.toLowerCase().includes('logo-blue')) {
        const dynamicMainImage = selectedSize === 'XL'
          ? `${baseUrl}/images/products/mousepads/xl/xl_blue/Generated Image October 30, 2025 - 6_25PM.png`
          : `${baseUrl}/images/products/mousepads/l/l_blue/Generated Image October 30, 2025 - 6_09PM.png`;

        if (selectedSize === 'XL') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_01.webp',
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_02.webp',
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_03.webp',
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_04.webp'
          ];
        } else {
          return [
            dynamicMainImage,
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_01.webp',
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_02.webp',
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_03.webp',
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_04.webp'
          ];
        }
      }

      // Geoid mousepads - size and color based
      const dynamicMainImage = getGeoidMainImage(selectedSize, selectedColor);

      if (selectedSize === 'XL') {
        if (selectedColor === 'red') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/xl/xl_red/logo-red_red_xl_01.webp',
            '/images/products/mousepads/xl/xl_red/logo-red_red_xl_02.webp',
            '/images/products/mousepads/xl/xl_red/logo-red_red_xl_03.webp',
            '/images/products/mousepads/xl/xl_red/logo-red_red_xl_04.webp'
          ];
        } else if (selectedColor === 'blue') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_01.webp',
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_02.webp',
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_03.webp',
            '/images/products/mousepads/xl/xl_blue/logo-blue_blue_xl_04.webp'
          ];
        } else if (selectedColor === 'white') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/xl/xl_white_geoid/geoid_white_xl_01.webp',
            '/images/products/mousepads/xl/xl_white_geoid/geoid_white_xl_02.webp',
            '/images/products/mousepads/xl/xl_white_geoid/geoid_white_xl_03.webp'
          ];
        } else {
          // black by default
          return [
            dynamicMainImage,
            '/images/products/mousepads/xl/xl_black_geoid/geoid_black_xl_01.webp',
            '/images/products/mousepads/xl/xl_black_geoid/geoid_black_xl_02.webp',
            '/images/products/mousepads/xl/xl_black_geoid/geoid_black_xl_03.webp'
          ];
        }
      } else {
        // Size L
        if (selectedColor === 'red') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/l/l_red/logo-red_red_l_01.webp',
            '/images/products/mousepads/l/l_red/logo-red_red_l_02.webp',
            '/images/products/mousepads/l/l_red/logo-red_red_l_03.webp',
            '/images/products/mousepads/l/l_red/logo-red_red_l_04.webp'
          ];
        } else if (selectedColor === 'blue') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_01.webp',
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_02.webp',
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_03.webp',
            '/images/products/mousepads/l/l_blue/logo-blue_blue_l_04.webp'
          ];
        } else if (selectedColor === 'white') {
          return [
            dynamicMainImage,
            '/images/products/mousepads/l/l_white_geoid/geoid_white_l_01.webp',
            '/images/products/mousepads/l/l_white_geoid/geoid_white_l_02.webp',
            '/images/products/mousepads/l/l_white_geoid/geoid_white_l_03.webp',
            '/images/products/mousepads/l/l_white_geoid/geoid_white_l_04.webp'
          ];
        } else {
          // black by default
          return [
            dynamicMainImage,
            '/images/products/mousepads/l/l_black_geoid/geoid_black_l_01.webp',
            '/images/products/mousepads/l/l_black_geoid/geoid_black_l_02.webp',
            '/images/products/mousepads/l/l_black_geoid/geoid_black_l_03.webp',
            '/images/products/mousepads/l/l_black_geoid/geoid_black_l_04.webp'
          ];
        }
      }
    }

    // For clothing - dynamic images based on selected color
    if (productData.category === 'clothing' && productData.images && productData.images.length > 0) {
      const originalColor = productData.color;

      // If selected color is the same as original, return original images
      if (originalColor && selectedColor === originalColor) {
        return productData.images || [mainImage, mainImage, mainImage];
      }

      // Try to find a product with the same subtitle and clothingType but different color
      // This is needed because black and white versions are separate products with different image filenames
      const alternateColorProduct = ALL_PRODUCTS.find((p: any) =>
        p.category === 'clothing' &&
        p.subtitle === productData.subtitle &&
        p.clothingType === productData.clothingType &&
        p.color === selectedColor
      );

      // If we found a product with the selected color, use its images
      if (alternateColorProduct && alternateColorProduct.images && alternateColorProduct.images.length > 0) {
        return alternateColorProduct.images;
      }

      // Fallback: try to replace color in paths (might not work if filenames are different)
      return productData.images ? productData.images.map(imagePath =>
        imagePath.replace(`_${originalColor}/`, `_${selectedColor}/`)
      ) : [mainImage, mainImage, mainImage];
    }

    // For other products with images array (sleeves, etc)
    if (productData.images && productData.images.length > 0) {
      return productData.images;
    }

    // Otherwise use main image
    return [mainImage, mainImage, mainImage];
  }, [productData, selectedSize, selectedColor]);
};

/**
 * Haptic Feedback Utility
 * 
 * Provides haptic vibration feedback on mobile devices
 * Enhances UX with tactile responses to user actions
 * 
 * Supports:
 * - Vibration API (most Android devices)
 * - Taptic Engine hint via pattern (iOS may support basic patterns)
 */

export type HapticType = 
  | 'light'      // Subtle feedback (10ms)
  | 'medium'     // Standard feedback (20ms)
  | 'heavy'      // Strong feedback (40ms)
  | 'success'    // Success pattern
  | 'warning'    // Warning pattern
  | 'error'      // Error pattern
  | 'selection'; // Selection change

const HAPTIC_PATTERNS: Record<HapticType, number | number[]> = {
  light: 10,
  medium: 20,
  heavy: 40,
  success: [10, 50, 10], // Double tap
  warning: [20, 100, 20, 100, 20], // Triple tap
  error: [40, 100, 40], // Strong double tap
  selection: 5, // Very light tap
};

/**
 * Trigger haptic feedback
 * 
 * @param type - Type of haptic feedback
 * @returns boolean - true if vibration was triggered successfully
 * 
 * @example
 * // Light tap on button press
 * triggerHaptic('light');
 * 
 * // Success feedback after adding to cart
 * triggerHaptic('success');
 * 
 * // Error feedback on validation failure
 * triggerHaptic('error');
 */
export const triggerHaptic = (type: HapticType = 'light'): boolean => {
  // Check if Vibration API is available
  if (!navigator.vibrate) {
    return false;
  }

  try {
    const pattern = HAPTIC_PATTERNS[type];
    navigator.vibrate(pattern);
    return true;
  } catch (error) {
    console.warn('Haptic feedback failed:', error);
    return false;
  }
};

/**
 * Cancel any ongoing vibration
 */
export const cancelHaptic = (): void => {
  if (navigator.vibrate) {
    navigator.vibrate(0);
  }
};

/**
 * Check if device supports haptic feedback
 */
export const isHapticSupported = (): boolean => {
  return 'vibrate' in navigator;
};

/**
 * React Hook for haptic feedback
 * 
 * @example
 * const handleClick = useHaptic('medium', () => {
 *   // Your click handler logic
 * });
 */
export const useHapticFeedback = () => {
  const trigger = (type: HapticType = 'light') => {
    return triggerHaptic(type);
  };

  return {
    trigger,
    isSupported: isHapticSupported(),
    cancel: cancelHaptic
  };
};

// Specific haptic helper functions
export const hapticLight = () => triggerHaptic('light');
export const hapticMedium = () => triggerHaptic('medium');
export const hapticHeavy = () => triggerHaptic('heavy');
export const hapticSuccess = () => triggerHaptic('success');
export const hapticWarning = () => triggerHaptic('warning');
export const hapticError = () => triggerHaptic('error');
export const hapticSelection = () => triggerHaptic('selection');

export default {
  trigger: triggerHaptic,
  cancel: cancelHaptic,
  isSupported: isHapticSupported,
  light: hapticLight,
  medium: hapticMedium,
  heavy: hapticHeavy,
  success: hapticSuccess,
  warning: hapticWarning,
  error: hapticError,
  selection: hapticSelection,
};

/**
 * Utility function to get the correct public URL for assets
 * Handles both development and production (GitHub Pages) environments
 */
export const getPublicUrl = (path: string): string => {
  // Remove leading slash if present
  const cleanPath = path.startsWith('/') ? path.slice(1) : path;
  
  // In development, PUBLIC_URL is usually empty or '/'
  // In production (GitHub Pages), it's '/RecrentShop'
  const publicUrl = process.env.PUBLIC_URL || '';
  
  // If publicUrl is empty or just '/', return path as is
  if (!publicUrl || publicUrl === '/') {
    return `/${cleanPath}`;
  }
  
  return `${publicUrl}/${cleanPath}`;
};

/**
 * Get image URL with proper public URL prefix
 */
export const getImageUrl = (imagePath: string): string => {
  return getPublicUrl(imagePath);
};

/**
 * Fix image paths for GitHub Pages deployment
 * This function is used to automatically fix all image paths in the app
 */
export const fixImagePath = (path: string): string => {
  if (!path) return path;

  // If path already includes PUBLIC_URL, return as is
  if (path.includes(process.env.PUBLIC_URL || '')) {
    return path;
  }

  // If path starts with /, it's an absolute path
  if (path.startsWith('/')) {
    return getPublicUrl(path);
  }

  return path;
};

/**
 * Conditionally join classNames together
 * Filters out falsy values and joins with space
 *
 * @example
 * cn('btn', isActive && 'active', 'text-white') // 'btn active text-white'
 */
export function cn(...classes: (string | boolean | undefined | null)[]): string {
  return classes.filter(Boolean).join(' ');
}

/**
 * Throttle function to limit execution rate
 * Useful for scroll/resize event handlers
 */
export function throttle<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let lastCall = 0;
  return (...args: Parameters<T>) => {
    const now = Date.now();
    if (now - lastCall >= delay) {
      lastCall = now;
      func(...args);
    }
  };
}

/**
 * Clamp a number between min and max values
 */
export function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

